import{_ as i,c as a,o as n,a1 as l}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Versiones: Historial | Agent Skills","description":"Ver el registro de actualizaciones y cambios funcionales del proyecto Agent Skills.","frontmatter":{"title":"Versiones: Historial | Agent Skills","sidebarTitle":"Versiones","subtitle":"Versiones: Historial","description":"Ver el registro de actualizaciones y cambios funcionales del proyecto Agent Skills.","tags":["changelog","actualizaciones","versiones"]},"headers":[],"relativePath":"es/vercel-labs/agent-skills/changelog/releases/index.md","filePath":"es/vercel-labs/agent-skills/changelog/releases/index.md"}'),o={name:"es/vercel-labs/agent-skills/changelog/releases/index.md"};function s(r,e,t,c,d,p){return n(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="historial-de-versiones" tabindex="-1">Historial de versiones <a class="header-anchor" href="#historial-de-versiones" aria-label="Permalink to &quot;Historial de versiones&quot;">​</a></h1><p>Este proyecto registra todas las actualizaciones de funcionalidad, mejoras y correcciones de versiones.</p><hr><h2 id="v1-0-0-enero-2026" tabindex="-1">v1.0.0 - Enero 2026 <a class="header-anchor" href="#v1-0-0-enero-2026" aria-label="Permalink to &quot;v1.0.0 - Enero 2026&quot;">​</a></h2><h3 id="🎉-lanzamiento-inicial" tabindex="-1">🎉 Lanzamiento inicial <a class="header-anchor" href="#🎉-lanzamiento-inicial" aria-label="Permalink to &quot;🎉 Lanzamiento inicial&quot;">​</a></h3><p>Esta es la primera versión oficial de Agent Skills, que incluye paquetes de habilidades y herramientas de compilación completas.</p><h4 id="nuevas-funcionalidades" tabindex="-1">Nuevas funcionalidades <a class="header-anchor" href="#nuevas-funcionalidades" aria-label="Permalink to &quot;Nuevas funcionalidades&quot;">​</a></h4><p><strong>Reglas de optimización de rendimiento de React</strong></p><ul><li>40+ reglas de optimización de rendimiento de React/Next.js</li><li>8 categorías principales: eliminación de cascadas, optimización de paquetes, rendimiento del servidor, optimización de re-render, etc.</li><li>Clasificado por nivel de impacto (CRITICAL &gt; HIGH &gt; MEDIUM &gt; LOW)</li><li>Cada regla incluye comparación de ejemplos de código Incorrecto/Correcto</li></ul><p><strong>Implementación con un clic en Vercel</strong></p><ul><li>Soporta detección automática de más de 40 marcos principales</li><li>Proceso de implementación sin autenticación</li><li>Genera automáticamente enlaces de vista previa y transferencia de propiedad</li><li>Soporte para proyectos HTML estáticos</li></ul><p><strong>Guías de diseño web</strong></p><ul><li>100+ reglas de diseño de interfaces web</li><li>Auditoría multidimensional de accesibilidad, rendimiento y experiencia de usuario</li><li>Extracción remota de las últimas reglas (desde GitHub)</li></ul><p><strong>Herramientas de compilación</strong></p><ul><li><code>pnpm build</code> - genera documentación completa de reglas AGENTS.md</li><li><code>pnpm validate</code> - verifica la integridad de archivos de reglas</li><li><code>pnpm extract-tests</code> - extrae casos de prueba</li><li><code>pnpm dev</code> - flujo de trabajo de desarrollo (build + validate)</li></ul><h4 id="pila-tecnologica" tabindex="-1">Pila tecnológica <a class="header-anchor" href="#pila-tecnologica" aria-label="Permalink to &quot;Pila tecnológica&quot;">​</a></h4><ul><li>TypeScript 5.3.0</li><li>Node.js 20+</li><li>pnpm 10.24.0+</li><li>tsx 4.7.0 (tiempo de ejecución de TypeScript)</li></ul><h4 id="documentacion" tabindex="-1">Documentación <a class="header-anchor" href="#documentacion" aria-label="Permalink to &quot;Documentación&quot;">​</a></h4><ul><li>Documentación completa de reglas AGENTS.md</li><li>Archivos de definición de habilidades SKILL.md</li><li>Instrucciones de instalación y uso en README.md</li><li>Documentación completa de herramientas de compilación</li></ul><hr><h2 id="especificacion-de-versiones" tabindex="-1">Especificación de versiones <a class="header-anchor" href="#especificacion-de-versiones" aria-label="Permalink to &quot;Especificación de versiones&quot;">​</a></h2><p>El proyecto sigue el control de versiones semántica (Semantic Versioning):</p><ul><li><strong>Número de versión principal (Major)</strong>: cambios incompatibles en la API</li><li><strong>Número de versión secundaria (Minor)</strong>: nuevas funcionalidades compatibles con versiones anteriores</li><li><strong>Número de revisión (Patch)</strong>: correcciones de errores compatibles con versiones anteriores</li></ul><p>Ejemplo: <code>1.0.0</code> indica la primera versión estable.</p>',24)])])}const g=i(o,[["render",s]]);export{u as __pageData,g as default};
